DROP TRIGGER IF EXISTS set_suppliers_updated_at ON public.suppliers; CREATE TRIGGER set_suppliers_updated_at BEFORE UPDATE ON public.suppliers FOR EACH ROW EXECUTE FUNCTION set_current_timestamp_updated_at();
