DROP TRIGGER IF EXISTS trg_prevent_ledger_batches_mutation ON public.ledger_batches; CREATE TRIGGER trg_prevent_ledger_batches_mutation BEFORE DELETE OR UPDATE ON public.ledger_batches FOR EACH ROW WHEN ((old.status = 'POSTED'::text)) EXECUTE FUNCTION prevent_ledger_mutation();
