DROP TRIGGER IF EXISTS trg_log_stock_ledger ON public.stock_levels; CREATE TRIGGER trg_log_stock_ledger AFTER UPDATE ON public.stock_levels FOR EACH ROW WHEN ((new.qty IS DISTINCT FROM old.qty)) EXECUTE FUNCTION log_stock_ledger_on_update();
DROP TRIGGER IF EXISTS tr_sync_user_name ON public.users; CREATE TRIGGER tr_sync_user_name BEFORE INSERT OR UPDATE OF full_name ON public.users FOR EACH ROW EXECUTE FUNCTION sync_user_name();
